U-64.example:
# Debian/Ubuntu 자동 보안 패치 설정
sudo apt install unattended-upgrades apt-listchanges -y
sudo dpkg-reconfigure unattended-upgrades

# /etc/apt/apt.conf.d/50unattended-upgrades 파일 편집
Unattended-Upgrade::Allowed-Origins {
    "${distro_id}:${distro_codename}-security";
};
Unattended-Upgrade::AutoFixInterruptedDpkg "true";
Unattended-Upgrade::SyslogReport "on";

# RHEL/CentOS 자동 업데이트 설정
sudo yum install yum-cron -y
sudo systemctl enable yum-cron
sudo systemctl start yum-cron

# /etc/yum/yum-cron.conf 편집
apply_updates = yes

# 현재 보안 패치 상태 확인
aptitude search '~U~Vpriority(required|important)' # Debian/Ubuntu
yum check-update --security # CentOS/RHEL

