List<String> allowedRedirects = Arrays.asList("https://example.com", "https://trusted.com");
String redirectUrl = request.getParameter("redirect");

if (allowedRedirects.contains(redirectUrl)) {
  response.sendRedirect(redirectUrl);
} else {
