  res.redirect(redirectUrl);
} else {
  res.redirect('/');
}

WEB-24.example:
# 디렉토리 생성 및 권한 설정
mkdir -p /var/uploads
chown www-data:www-data /var/uploads
chmod 755 /var/uploads

# Apache .htaccess 설정 (/var/uploads/.htaccess)
<FilesMatch "\\.php$">
  Deny from all
</FilesMatch>
AddType text/plain .php .php3 .php4 .php5 .phtml

